code = """import json, re

business_data_path = var_functions.query_db:6
business_results = json.load(open(business_data_path))

print("Total businesses:", len(business_results))

def extract_categories(description):
    if not description:
        return []
    match = re.search(r'services? in(?:cluding)?(?: the (?:fields|categories) of)?\s+(.+?)(?:\.|$)', description, re.I)
    if match:
        categories = re.split(r',| and ', match.group(1), flags=re.I)
        return [cat.strip() for cat in categories if cat.strip()]
    return []

test_samples = []
for i in range(5):
    biz = business_results[i]
    desc = biz.get('description', '')
    cats = extract_categories(desc)
    test_samples.append({'business_id': biz.get('business_id'), 'categories': cats})
    print("Sample", i+1, ":", cats)

print("__RESULT__:")
print(json.dumps({'total_businesses': len(business_results), 'samples': test_samples}))"""

